#include <omp.h>
#include <stdbool.h>
#include <stdio.h>

#define fp float

typedef struct record {
	int value;
} record;

typedef struct knode {
	int location;
	int indices[DEFAULT_ORDER + 1];
	int keys[DEFAULT_ORDER + 1];
	bool is_leaf;
	int num_keys;
} knode;

void findK(	long height,
			knode *knodesD,
			long knodes_elem,
			record *recordsD,

			long *currKnodeD,
			long *offsetD,
			int *keysD,
			record *ansD,
			int order,
			int count) {

	// Parallel over count queries
#pragma omp parallel for
	for (int bid = 0; bid < count; bid++) {
		// Each thread simulates thid in OpenCL kernel: thid in [0, order-1]
		// Because OpenCL kernel launched with local_work_size = order and global_work_size = count * order

		long currKnode = currKnodeD[bid];
		long offset = offsetD[bid];
		int key = keysD[bid];

		for (int i = 0; i < height; i++) {
			// For each i, find the thid s.t keys[thid] <= key < keys[thid+1]
			int found_thid = -1;
			for (int thid = 0; thid < order; thid++) {
				int key_thid = knodesD[currKnode].keys[thid];
				int key_thid1 = knodesD[currKnode].keys[thid + 1];
				if ((key_thid <= key) && (key_thid1 > key)) {
					// Check indices bound
					if (knodesD[offset].indices[thid] < knodes_elem) {
						offset = knodesD[offset].indices[thid];
					}
					found_thid = thid;
					break;
				}
			}
			currKnode = offset;
		}

		// At leaf level, find thid s.t keys[thid] == key, assign ansD[bid].value = recordsD[indices[thid]].value
		int found_thid = -1;
		for (int thid = 0; thid < order; thid++) {
			if (knodesD[currKnode].keys[thid] == key) {
				found_thid = thid;
				break;
			}
		}
		if (found_thid != -1) {
			int idx = knodesD[currKnode].indices[found_thid];
			if (idx < knodes_elem)
				ansD[bid].value = recordsD[idx].value;
			else
				ansD[bid].value = -1;
		} else {
			ansD[bid].value = -1;
		}
	}
}

