#include <omp.h>
#include <stdbool.h>
#include <stdio.h>

#define fp float

typedef struct knode {
	int location;
	int indices[DEFAULT_ORDER_2 + 1];
	int keys[DEFAULT_ORDER_2 + 1];
	bool is_leaf;
	int num_keys;
} knode;

void findRangeK(	long height,
					knode *knodesD,
					long knodes_elem,

					long *currKnodeD,
					long *offsetD,
					long *lastKnodeD,
					long *offset_2D,
					int *startD,
					int *endD,
					int *RecstartD,
					int *ReclenD,
					int order,
					int count) {

	// Parallel over count queries
#pragma omp parallel for
	for (int bid = 0; bid < count; bid++) {
		long currKnode = currKnodeD[bid];
		long offset = offsetD[bid];
		long lastKnode = lastKnodeD[bid];
		long offset_2 = offset_2D[bid];
		int start = startD[bid];
		int end = endD[bid];

		for (int i = 0; i < height; i++) {
			// Find thid for start key
			for (int thid = 0; thid < order; thid++) {
				int key_curr_thid = knodesD[currKnode].keys[thid];
				int key_curr_thid1 = knodesD[currKnode].keys[thid + 1];
				if ((key_curr_thid <= start) && (key_curr_thid1 > start)) {
					if (knodesD[currKnode].indices[thid] < knodes_elem) {
						offset = knodesD[currKnode].indices[thid];
					}
				}
				int key_last_thid = knodesD[lastKnode].keys[thid];
				int key_last_thid1 = knodesD[lastKnode].keys[thid + 1];
				if ((key_last_thid <= end) && (key_last_thid1 > end)) {
					if (knodesD[lastKnode].indices[thid] < knodes_elem) {
						offset_2 = knodesD[lastKnode].indices[thid];
					}
				}
			}
			currKnode = offset;
			lastKnode = offset_2;
		}

		// At leaf level, find thid s.t keys[thid] == start and assign RecstartD[bid]
		int recStartFound = -1;
		for (int thid = 0; thid < order; thid++) {
			if (knodesD[currKnode].keys[thid] == start) {
				RecstartD[bid] = knodesD[currKnode].indices[thid];
				recStartFound = thid;
				break;
			}
		}
		if (recStartFound == -1) {
			RecstartD[bid] = 0;
		}

		// Barrier simulated by all threads done above

		// Find thid s.t keys[thid] == end and assign ReclenD[bid]
		int recLenFound = -1;
		for (int thid = 0; thid < order; thid++) {
			if (knodesD[lastKnode].keys[thid] == end) {
				ReclenD[bid] = knodesD[lastKnode].indices[thid] - RecstartD[bid] + 1;
				recLenFound = thid;
				break;
			}
		}
		if (recLenFound == -1) {
			ReclenD[bid] = 0;
		}
	}
}
